import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { CategoryInfo, DataService, SearchResult } from './data.service';

@Component({
  selector: 'app-results',
  templateUrl: './results.component.html',
  styleUrls: ['./results.component.css'],
})
export class ResultsComponent implements OnInit {
  results: SearchResult[] = [];
  expanded: boolean[] = [];
  loading = true;
  error = '';
  categories: Record<string, CategoryInfo> = {};

  constructor(private route: ActivatedRoute, private router: Router, private dataService: DataService) {}

  ngOnInit(): void {
    this.route.queryParams.subscribe((params) => {
      const raw = params['data'];
      if (!raw) {
        this.error = 'Nessuna ricerca disponibile. Torna indietro e riprova.';
        this.loading = false;
        return;
      }
      try {
        this.results = JSON.parse(raw) as SearchResult[];
        this.expanded = this.results.map(() => false);
      } catch {
        this.error = 'Parametro di ricerca non valido.';
      }
      this.dataService.loadData().subscribe({
        next: () => {
          this.categories = this.dataService.getAllCategories();
          this.loading = false;
        },
        error: () => {
          this.loading = false;
        },
      });
    });
  }

  toggle(index: number): void {
    this.expanded[index] = !this.expanded[index];
  }

  getCategoryInfo(categoryId: string): CategoryInfo {
    return this.categories[categoryId] || {};
  }

  startTest(): void {
    const ids = this.results.map((item) => item.id);
    this.router.navigate(['/test'], { queryParams: { categorie: JSON.stringify(ids) } });
  }
}
<nav class="navbar-custom d-flex align-items-center justify-content-between flex-wrap gap-2">
  <a class="navbar-brand-text text-decoration-none" routerLink="/">Educazione Digitale Familiare</a>
  <a routerLink="/" class="btn-search" style="text-decoration:none;font-size:0.9rem;">Nuova ricerca</a>
</nav>

<section class="results-shell">
  <div class="section-label">Risultati della tua ricerca</div>
  <h2 class="section-title">Le aree più rilevanti per te</h2>
  <p class="section-sub">Clicca su una categoria per leggere la spiegazione e accedere al percorso guidato.</p>

  <div *ngIf="loading" class="info-box">Caricamento...</div>
  <div *ngIf="error" class="info-box info-box-error">{{ error }}</div>

  <div *ngIf="!loading && !error" class="results-list">
    <div class="risultato-card" *ngFor="let item of results; let i = index">
      <div class="risultato-header" (click)="toggle(i)">
        <span class="risultato-nome">{{ item.nome }}</span>
        <span class="risultato-arrow">{{ expanded[i] ? '▲' : '▼' }}</span>
      </div>
      <div class="risultato-desc" [style.display]="expanded[i] ? 'block' : 'none'">
        <p>{{ getCategoryInfo(item.id).descrizione || item.descrizione }}</p>
        <div *ngIf="item.link || getCategoryInfo(item.id).link" style="margin-top:1rem;">
          <a [href]="item.link || getCategoryInfo(item.id).link" target="_blank" class="btn-search" style="text-decoration:none;">Vai al percorso →</a>
        </div>
      </div>
    </div>

    <div class="results-actions">
      <button class="btn-primary-hero" (click)="startTest()">Crea il tuo patto familiare</button>
    </div>
  </div>
</section>
